% User inputs
L = input('Enter the length of the domain (L): ');
T = input('Enter the total time (T): ');
D = input('Enter the diffusion coefficient (D): ');
Nx = input('Enter the number of spatial points (Nx): ');
Nt = input('Enter the number of time steps (Nt): ');
dx = L / (Nx - 1);
dt = T / Nt;

% Initialize solution array
u = zeros(Nx, Nt + 1);

% Initial condition: Gaussian distribution
x = linspace(0, L, Nx);
u(:,1) = exp(-(x - L/2).^2 / (2*(L/4)^2));

% Boundary conditions
u(1,:) = 0; % u(0,t) = 0
u(Nx,:) = 0; % u(L,t) = 0

