import java.util.Scanner;

public class TitleCaseConverter {
    public static void main(String[] args) {
        // Create a Scanner object to read user input
        Scanner scanner = new Scanner(System.in);

        // Prompt the user to enter a string
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Convert the string to title case
        String titleCaseString = toTitleCase(input);

        // Display the converted string
        System.out.println("Title case: " + titleCaseString);

        // Close the scanner
        scanner.close();
    }

    /**
     * Converts a given string to title case.
     * 
     * @param input The input string to be converted.
     * @return The converted string in title case.
     */
    public static String toTitleCase(String input) {
        if (input == null || input.isEmpty()) {
            return input;
        }

        StringBuilder titleCase = new StringBuilder();
        boolean nextTitleCase = true;

        for (char c : input.toCharArray()) {
            if (Character.isSpaceChar(c)) {
                nextTitleCase = true;
            } else if (nextTitleCase) {
                c = Character.toTitleCase(c);
                nextTitleCase = false;
            } else {
                c = Character.toLowerCase(c);
            }
            titleCase.append(c);
        }

        return titleCase.toString();
    }
}
```

### Explanation:
1. **Scanner Object**: We use `Scanner` to read the user's input.
2. **prompt**: The user is prompted to enter a string.
