    for (int i = 1; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (sequence[i] > sequence[j] && lis[i] < lis[j] + 1) {
                lis[i] = lis[j] + 1;
            }
        }
    }

    // Pick maximum of all LIS values
    int max_lis = *std::max_element(lis.begin(), lis.end());

    std::cout << "The length of the longest increasing subsequence is: " << max_lis << std::endl;

    return 0;
}
